SELECT [DDT_Picking Line].No_, [DDT_Picking Line].[Constant Variable Code], [DDT_Picking Line].[Assortment Code], [DDT_Picking Line].[Location Code], [DDT_Picking Line].[Document Type], [DDT_Picking Header].STATUS, Sum(Val([Quantity])) AS QTY
FROM [DDT_Picking Header] INNER JOIN [DDT_Picking Line] ON [DDT_Picking Header].No_ = [DDT_Picking Line].[Document No_]
GROUP BY [DDT_Picking Line].No_, [DDT_Picking Line].[Constant Variable Code], [DDT_Picking Line].[Assortment Code], [DDT_Picking Line].[Location Code], [DDT_Picking Line].[Document Type], [DDT_Picking Header].STATUS
HAVING ((([DDT_Picking Line].No_)="F5MURRAY01/LES") AND (([DDT_Picking Line].[Constant Variable Code])="NVY/GRY") AND (([DDT_Picking Line].[Assortment Code])="BM01" Or ([DDT_Picking Line].[Assortment Code])="BM08") AND (([DDT_Picking Line].[Location Code])="PMAG") AND (([DDT_Picking Line].[Document Type])=0) AND (([DDT_Picking Header].STATUS)=1)) OR ((([DDT_Picking Line].No_)="F5OLYMPIA11/GLI") AND (([DDT_Picking Line].[Constant Variable Code])="DKB") AND (([DDT_Picking Line].[Assortment Code])="BW07" Or ([DDT_Picking Line].[Assortment Code])="BW08") AND (([DDT_Picking Line].[Location Code])="PMAG") AND (([DDT_Picking Line].[Document Type])=0) AND (([DDT_Picking Header].STATUS)=1));

